import{_ as e,o as i,c as n,e as s}from"./app-9ee1dfa4.js";const d={},l=s(`<h1 id="пакетныи-менеджер-yum" tabindex="-1"><a class="header-anchor" href="#пакетныи-менеджер-yum" aria-hidden="true">#</a> Пакетный менеджер YUM</h1><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>yum help (отображение команд и опций)
yum list (список названий пакетов из репозиторий)
yum list available (список всех доступных пакетов)
yum list installed (список всех установленных пакетов)
yum list installed httpd (установлен ли указанный пакет)
yum list all (список установленных и доступных пакетов)
yum list kernel (список пакетов, относящихся к ядру)
yum info httpd (отображение информации о пакете)
yum deplist httpd (список зависимостей и необходимых пакетов)
yum provides &quot;*bin/top&quot; (найти пакет, который содержит файл)
yum search httpd (поиск пакета по имени и описанию)
yum updateinfo list security (получить информацию о доступных обновлениях безопасности)
yum grouplist (вывести список групп)
yum groupinfo &quot;Basic Web Server&quot; (вывести описание и содержимое группы)
yum groupinstall &quot;Basic Web Server&quot; (установка группы пакетов «Basic Web Server»)
yum groupremove &quot;Basic Web Server&quot; (удаление группы)
yum check-update (Проверка на доступные обновления)
yum repolist (список подключенных репозиториев)
yum repoinfo epel (информация об определенном репозитории)
yum repo-pkgs epel list (информация о пакетах в указанном репозитории)
yum repo-pkgs reponame install (установить все пакеты из репозитория)
yum repo-pkgs reponame remove (удалить пакеты установленные из репозитория)
yum makecache (создать кэш)
yum check (проверить локальную базу rpm (поддерживаются параметры dependencies, duplicates, obsoletes, provides))
yum history list (просмотр yum истории (вывод списка транзакций))
yum history info 9 (просмотр информации определенной транзакции (установленные пакеты, установленные зависимости))
yum history undo 9 (отмена транзакции)
yum history redo 9 (повторить)
yum clean packages (удалить пакеты сохраненные в кэше)
yum clean all (удалить все пакеты и метаданные)
yum install httpd (установить пакет)
yum remove httpd (удаление пакета)
yum update httpd (обновить пакет)
yum update (обновить все пакеты)
yum update-to (обновить до определенной версии)
yum localinstall httpd.rpm (установить из локальной директории (поиск/установка зависимостей будут произведены из подключенных репозиториев) )
yum localinstall http://server/repo/httpd.rpm (установить с http)
yum downgrade (откатиться к предыдущей версии пакета)
yum reinstall httpd (переустановка пакета (восстановление удаленных файлов))
yum autoremove (удаление ненужных более пакетов)

yum-cron (установка обновлений по расписанию (yum-cron устанавливается отдельно))
createrepo (создание локальных репозиториев (createrepo ставится отдельно))
cat /var/log/yum.log (дополнительно можно просмотреть лог)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="опции" tabindex="-1"><a class="header-anchor" href="#опции" aria-hidden="true">#</a> Опции</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>-y (ответить «yes» при запросе)
--assumeno (ответить «no» при запросе)
--noplugins (использовать Yum без плагинов)
--disableplugin=fastestmirror (отключить определенный плагин)
--enableplugin=ps (включить плагины, которые установлены, но отключены)
yum update -y --enablerepo=epel (включить отключенный репозиторий)
yum update -y --disablerepo=epel (отключить репозиторий)
yum install httpd --downloadonly (скачать пакеты, но не устанавливать (на Centos 7 x86_64 будут скачаны в &#39;/var/cache/yum/x86_64/7/base/packages/&#39;))
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="команды-доступные-после-установки-пакета-yum-utils" tabindex="-1"><a class="header-anchor" href="#команды-доступные-после-установки-пакета-yum-utils" aria-hidden="true">#</a> Команды доступные после установки пакета yum-utils</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>find-repos-of-install httpd (найти из какого репозитория установлен пакет)
needs-restarting (найти процессы, пакеты которых обновлены и требуют рестарта)
repoquery  --requires --resolve httpd (запрос к репозиторию, узнать зависимости пакета, не устанавливая его)
reposync -p repo1 --repoid=updates (синхронизировать yum репозиторий updates в локальную директорию repo1)
verifytree URL (проверить локальный репозиторий на целостность)
yum-complete-transaction (завершить транзакции)
yum-builddep (установить необходимые зависимости для сборки RPM пакета)
yum-config-manager (управление конфигурационными опциями и репозиториями yum )
yumdb info httpd (запрос к локальной базе yum, отображение информации о пакете (использованная команда, контрольная сумма, URL с которого был установлен и другое))
yumdownloader (скачать rpm пакеты из репозитория)
yumdownloader --source php (скачать src.rpm пакет из репозитория (должен быть подключен соответствующий репозиторий, например в &#39;/etc/yum.repos.d/CentOS-Sources.repo&#39; в CentOS))
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="конфигурационные-фаилы-yum-и-их-расположение" tabindex="-1"><a class="header-anchor" href="#конфигурационные-фаилы-yum-и-их-расположение" aria-hidden="true">#</a> Конфигурационные файлы Yum и их расположение</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>/etc/yum.conf (Основной конфигурационный файл)
/etc/yum/ (директория, с конфигурациями (например, yum плагины))
/etc/yum.repos.d/ (директория, содержащая информацию о репозиториях)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="некоторые-опции-yum-conf" tabindex="-1"><a class="header-anchor" href="#некоторые-опции-yum-conf" aria-hidden="true">#</a> Некоторые опции yum.conf</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>cachedir=/var/cache/yum/$basearch/$releasever (Директория, где yum хранит кэш и файлы базы (по умолчанию &#39;/var/cache/yum&#39;))
keepcache=1 (Определяет должен или нет Yum хранить кэш заголовков и пакетов после успешной установки. Значения: 0 или 1. (по умолчанию 1))
debuglevel=2 (уровень вывода отладочных сообщений. Значения: 1-10 (по умолчанию 2))
logfile=/var/log/yum.log (лог файл (по умолчанию &#39;/var/log/yum.log&#39;))
obsoletes=1 (обновлять устаревшие пакеты)
gpgcheck=1 (проверка подписи пакетов. Значения: 0 или 1 (по умолчанию 1))
plugins=1 (включение плагинов. Значения: 0 или 1 (по умолчанию 1))
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="некоторые-полезные-плагины" tabindex="-1"><a class="header-anchor" href="#некоторые-полезные-плагины" aria-hidden="true">#</a> Некоторые полезные плагины</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>yum-plugin-changelog (Добавляет опцию командной строки для просмотра ченжлога перед/после обновлениями)
yum-plugin-fastestmirror (выбирает более быстрые репозитории из списка зеркал)
yum-plugin-keys (добавляет команды keys, keys-info, keys-data, keys-remove, которые позволяют работать с ключами)
yum-plugin-versionlock (блокировать указанные пакеты от обновления, команда yum versionlock)
yum-plugin-verify (добавление команд yum verify-all, verify-multilib, verify-rpm для проверки контрольных сумм пакетов)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="работа-yum-через-прокси-сервер" tabindex="-1"><a class="header-anchor" href="#работа-yum-через-прокси-сервер" aria-hidden="true">#</a> Работа Yum через прокси сервер</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>proxy=&quot;http://server:3128&quot; (Для всех пользователей: добавить в секцию [main] в /etc/yum.conf)
proxy_proxy_username=user proxy_password=pass (при необходимости указать пароль, добавить)
export http_proxy=&quot;http://server:3128&quot; (указать прокси для отдельного пользователя)
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,14),a=[l];function r(u,m){return i(),n("div",null,a)}const t=e(d,[["render",r],["__file","rpm.html.vue"]]);export{t as default};
